from typing import List

def solve(s: str, order: List[int], k: int) -> int:
    n = len(s)

    def count_valid_substrings(s: str, replaced: List[bool]) -> int:
        count = 0
        n = len(s)
        for i in range(n):
            j = i
            while j < n and not replaced[j]:
                j += 1
            if j < n:
                count += (n - j) * (j - i + 1)
        return count

    left, right = 0, n
    result = -1

    while left <= right:
        mid = (left + right) // 2
        replaced = [False] * n
        for i in range(mid):
            replaced[order[i]] = True
        valid_count = count_valid_substrings(s, replaced)
        if valid_count >= k:
            result = mid
            right = mid - 1
        else:
            left = mid + 1

    return result
